const data = $input.first().json;
if (data.error || data.loggedOut) {
  return [];
}
// Aktuelle Top 5 – nicht nur "unread", sonst werden gelesene Nachrichten übersprungen
const items = (data.items || []).slice(0, 5);
if (!items.length) return [];
return items.map(i => ({ json: i }));

try {
const thread = $input.item.json;
const listItem = $('🔍 Nur ungelesene').item.json;

const messages = thread.messages || [];
if (!messages.length) return [];

// Letztes Message muss eingehend sein – sonst bereits beantwortet
const lastMsg = messages[messages.length - 1];
if (!lastMsg || lastMsg.own) return [];

// Schon ein KI-Draft → überspringen
if (thread.draft) return [];

// Kompliment → automatisch als gelesen markieren, kein Draft nötig
const isKompliment = messages.some(m => m.isKompliment);
if (isKompliment) {
  try {
    await this.helpers.httpRequest({
      method: 'POST',
      url: 'http://f3-cookie-crawler:3000/messages/mark-read',
      headers: { 'Content-Type': 'application/json' },
      body: { convId: listItem.id, convUrl: listItem.url },
      json: true, timeout: 20000
    });
    console.log('Kompliment auto-gelesen:', listItem.name);
  } catch(e) { console.log('mark-read Fehler:', e.message); }
  return []; // kein Draft für Komplimente
}

const recent = messages.slice(-10);
const history = recent.map(m => {
  const who = m.own ? 'Tobi (ich)' : listItem.name;
  return who + ': ' + m.text;
}).join('\n');

// Event Knowledge Base laden (Preise, Dresscode, Beschreibung)
let eventKnowledge = '';
try {
  const kb = await this.helpers.httpRequest({
    method: 'GET',
    url: 'http://f3-cookie-crawler:3000/status/event-knowledge',
    timeout: 5000
  });
  const entries = (kb?.data?.knowledge || kb?.knowledge || []);
  if (entries.length) {
    eventKnowledge = entries.map(e =>
      '=== ' + e.name + ' (' + e.datum + ') ===\n' +
      'Link: ' + e.link + '\n' +
      'Preise: ' + e.preise + '\n' +
      'Dresscode: ' + e.dresscode + '\n' +
      (e.uhrzeit ? 'Einlass/Beginn: ' + e.uhrzeit + ' Uhr\n' : '') +
      (e.kapazitaet ? 'Kapazität: ' + e.kapazitaet + ' Personen\n' : '') +
      'Info: ' + e.beschreibung.substring(0, 400)
    ).join('\n\n');
  }
} catch(e) {
  console.log('Knowledge Base nicht verfügbar:', e.message);
}

// Profil-Wissen laden (LV-Regeln, Hygiene, FFF-Infoseiten)
let profileKnowledge = '';
try {
  const pk = await this.helpers.httpRequest({
    method: 'GET',
    url: 'http://f3-cookie-crawler:3000/status/profile-knowledge',
    timeout: 5000
  });
  const pages = pk?.data?.pages || pk?.pages || [];
  if (pages.length) {
    profileKnowledge = pages
      .filter(p => p.text && p.text.length > 50)
      .map(p => '=== ' + (p.title || p.url) + ' ===\n' + p.text.substring(0, 600))
      .join('\n\n');
  }
} catch(e) {
  console.log('Profile-Knowledge nicht verfügbar:', e.message);
}

return [{ json: {
  name: listItem.name,
  lastMessage: lastMsg.text,
  history,
  gender: listItem.gender || null,
  eventKnowledge,
  profileKnowledge
}}];
} catch(e) {
  console.error('Kontext aufbereiten error:', e.message);
  return [];
}

